import numpy as np
from scipy.optimize import brentq

# Gompertz: y = exp(-exp(-r*(t-t50)))
# Check its asymmetry
def asym_gompertz():
    def f(t, r=1.0, t50=0.0):
        return np.exp(-np.exp(-r*(t-t50)))
    def find_t(level, lo=-50, hi=50):
        return brentq(lambda t: f(t) - level, lo, hi)
    t10 = find_t(0.1); t50 = find_t(0.5); t90 = find_t(0.9)
    return (t50 - t10) / (t90 - t10)

print(f'Gompertz asymmetry: {asym_gompertz():.3f}')

# Hill sigmoid: y = t^n / (K^n + t^n) - asymmetry in log space
# In log space: y = 1/(1 + exp(-n*(log(t)-log(K)))) = standard logistic in log(t)
# So Hill in log-time is symmetric. Not helpful directly.

# What about: y = 1 - exp(-exp(r*(lt - halftime))) ? (reversed Gompertz)
def asym_rev_gompertz():
    def f(t, r=1.0, t50=0.0):
        return 1.0 - np.exp(-np.exp(r*(t-t50)))
    def find_t(level, lo=-50, hi=50):
        return brentq(lambda t: f(t) - level, lo, hi)
    t10 = find_t(0.1); t50 = find_t(0.5); t90 = find_t(0.9)
    return (t50 - t10) / (t90 - t10)

print(f'Reversed Gompertz asymmetry: {asym_rev_gompertz():.3f}')

# Stretched exponential / Weibull CDF: y = 1 - exp(-(t/K)^beta)
# Check asymmetry for various beta
def asym_weibull(beta):
    def f(t):
        return 1.0 - np.exp(-(max(t,1e-10))**beta)
    def find_t(level, lo=1e-10, hi=1e6):
        return brentq(lambda t: f(t) - level, lo, hi)
    t10 = find_t(0.1); t50 = find_t(0.5); t90 = find_t(0.9)
    return (t50 - t10) / (t90 - t10)

for beta in [0.5, 1.0, 1.5, 2.0, 3.0, 4.0]:
    print(f'Weibull beta={beta:.1f}: asymmetry={asym_weibull(beta):.3f}')
"

