import numpy as np
from scipy.optimize import brentq

# Avrami/JMAK: y = 1 - exp(-(k*t)^n)
# In asinh-time: lt = asinh(x0), so x0 ~ exp(lt)/2 for large t
# We want: y = c0*(1 - exp(-(exp(lt - c2))^c3)) + c4
# = c0*(1 - exp(-exp(c3*(lt - c2)))) + c4   [Gompertz-like when c3=1]
# The term (exp(lt-c2))^c3 = exp(c3*(lt-c2))
# So this IS a Gompertz in lt-space!

# Check asymmetry of Gompertz in lt-space for various c3 (shape)
def asym_gompertz_lt(c3):
    def f(lt):
        return 1.0 - np.exp(-np.exp(c3*(lt - 0.0)))
    def find_lt(level, lo=-50, hi=50):
        return brentq(lambda lt: f(lt) - level, lo, hi)
    lt10 = find_lt(0.1); lt50 = find_lt(0.5); lt90 = find_lt(0.9)
    return (lt50 - lt10) / (lt90 - lt10)

print('Gompertz-in-lt-space asymmetry (all c3 give same shape):')
for c3 in [0.5, 1.0, 1.5, 2.0]:
    print(f'  c3={c3}: {asym_gompertz_lt(c3):.3f}')

# The Avrami in original time: y=1-exp(-(k*t)^n)
# After asinh transform: t ~ sinh(lt), so (k*sinh(lt))^n
# This is different from exp(n*lt)
# Let's check: Avrami in asinh-time space
def asym_avrami_asinh(n, k=1.0):
    def f(lt):
        t = np.sinh(lt)
        if t <= 0:
            return 0.0
        return 1.0 - np.exp(-(k*t)**n)
    def find_lt(level, lo=-10, hi=20):
        return brentq(lambda lt: f(lt) - level, lo, hi)
    lt10 = find_lt(0.1); lt50 = find_lt(0.5); lt90 = find_lt(0.9)
    return (lt50 - lt10) / (lt90 - lt10)

print('Avrami in asinh-time asymmetry:')
for n in [0.5, 1.0, 1.5, 2.0, 2.5, 3.0]:
    try:
        a = asym_avrami_asinh(n)
        print(f'  n={n}: {a:.3f}')
    except Exception as e:
        print(f'  n={n}: error {e}')
"

